window.REGISTER = [["saya", "aku", "私", "audio/w/saya.mp3", "audio/w/aku.mp3"], ["tidak", "nggak", "〜ない", "audio/w/tidak.mp3", "audio/w/nggak.mp3"], ["sudah", "udah", "もう〜した", "audio/w/sudah.mp3", "audio/w/udah.mp3"], ["saja", "aja", "〜だけ", "audio/w/saja.mp3", "audio/w/aja.mp3"], ["bagaimana", "gimana", "どう・どうやって", "audio/w/bagaimana.mp3", "audio/w/gimana.mp3"], ["ini", "nih", "これ（口語）", "audio/w/ini.mp3", "audio/w/nih.mp3"], ["mengapa", "kenapa", "なぜ", "audio/w/mengapa.mp3", "audio/w/kenapa.mp3"], ["sedang", "lagi", "〜している", "audio/w/sedang.mp3", "audio/w/lagi.mp3"], ["begini", "gini", "こんな風に", "audio/w/begini.mp3", "audio/w/gini.mp3"], ["teman", "temen", "友達（口語）", "audio/w/teman.mp3", "audio/w/temen.mp3"]];
window.MONTHS = [[1, "Januari", "audio/mon/1.mp3"], [2, "Februari", "audio/mon/2.mp3"], [3, "Maret", "audio/mon/3.mp3"], [4, "April", "audio/mon/4.mp3"], [5, "Mei", "audio/mon/5.mp3"], [6, "Juni", "audio/mon/6.mp3"], [7, "Juli", "audio/mon/7.mp3"], [8, "Agustus", "audio/mon/8.mp3"], [9, "September", "audio/mon/9.mp3"], [10, "Oktober", "audio/mon/10.mp3"], [11, "November", "audio/mon/11.mp3"], [12, "Desember", "audio/mon/12.mp3"]];
window.PREFIX = [{"p": "me- (meN-)", "t": "能動態・動詞をつくる", "note": "基本の接頭辞。語頭の音で mem-/men-/meng-/meny- に変化し、p・t・k・s は多く脱落します。", "ex": [["membaca", "読む（baca）", "audio/w/membaca.mp3"], ["menulis", "書く（tulis）", "audio/w/menulis.mp3"], ["memasak", "料理する（masak）", "audio/w/memasak.mp3"]]}, {"p": "ber-", "t": "自動詞「〜を持つ／〜の状態」", "note": "目的語をとらない動詞や状態。r で始まる語などは be- に（bekerja）。", "ex": [["bermain", "遊ぶ（main）", "audio/w/bermain.mp3"], ["berjalan", "歩く（jalan）", "audio/w/berjalan.mp3"], ["berbicara", "話す（bicara）", "audio/w/berbicara.mp3"]]}, {"p": "di-", "t": "受動態「〜される」", "note": "me- の能動に対し di- は受動。動作の受け手が主語になります。", "ex": [["dibaca", "読まれる（baca）", "audio/w/dibaca.mp3"], ["ditulis", "書かれる（tulis）", "audio/w/ditulis.mp3"], ["dimakan", "食べられる（makan）", "audio/w/dimakan.mp3"]]}, {"p": "ter-", "t": "「無意識に〜／最上級」", "note": "意図しない結果や、形容詞につけて最上級（terbaik=最良）。", "ex": [["terbuka", "開いている（buka）", "audio/w/terbuka.mp3"], ["terbaik", "最良の（baik）", "audio/w/terbaik.mp3"], ["tertidur", "眠り込む（tidur）", "audio/w/tertidur.mp3"]]}, {"p": "pe- (peN-)", "t": "「〜する人・道具」名詞", "note": "動作主や道具を表す名詞をつくります（me- と同じ音変化）。", "ex": [["pembaca", "読者（baca）", "audio/w/pembaca.mp3"], ["penulis", "作家（tulis）", "audio/w/penulis.mp3"], ["pekerja", "労働者（kerja）", "audio/w/pekerja.mp3"]]}, {"p": "per-", "t": "「〜にする」使役（命令形）", "note": "形容詞などを他動詞化。命令で使うことが多い（perbesar=大きくしろ）。", "ex": [["perbesar", "大きくする（besar）", "audio/w/perbesar.mp3"], ["perbaiki", "直す（baik）", "audio/w/perbaiki.mp3"], ["perjelas", "はっきりさせる（jelas）", "audio/w/perjelas.mp3"]]}, {"p": "ke-", "t": "序数・一部の名詞", "note": "数について序数（kedua=2番目）や、一部の名詞をつくります。", "ex": [["kedua", "2番目の（dua）", "audio/w/kedua.mp3"], ["ketiga", "3番目の（tiga）", "audio/w/ketiga.mp3"], ["ketua", "会長（tua）", "audio/w/ketua.mp3"]]}, {"p": "se-", "t": "「1つの／同じ」", "note": "「1」や「同じ・全体」を表します（seorang=1人、sekelas=同じクラス）。", "ex": [["seorang", "一人の（orang）", "audio/w/seorang.mp3"], ["sehari", "一日（hari）", "audio/w/sehari.mp3"], ["sekelas", "同じクラス（kelas）", "audio/w/sekelas.mp3"]]}, {"p": "memper-", "t": "使役「〜させる・より〜にする」", "note": "程度を強める使役。形容詞について「より〜にする」。", "ex": [["memperbesar", "拡大する（besar）", "audio/w/memperbesar.mp3"], ["memperbaiki", "修理する（baik）", "audio/w/memperbaiki.mp3"], ["mempercepat", "加速する（cepat）", "audio/w/mempercepat.mp3"]]}];
window.HISTORY = [{"title": "ジャワ原人", "body": "約100万年前、ジャワ島に古代人類が住んでいた。", "id": "Manusia purba pernah hidup di Pulau Jawa.", "ja": "古代人類はかつてジャワ島に住んでいました。", "audio": "audio/hist/h00.mp3"}, {"title": "祖先の渡来", "body": "約4000年前、海を渡って人々が移り住んだ。", "id": "Nenek moyang orang Indonesia datang dari laut.", "ja": "インドネシア人の祖先は海からやって来ました。", "audio": "audio/hist/h01.mp3"}, {"title": "稲作の始まり", "body": "稲作と金属器が社会を発展させた。", "id": "Orang dulu mulai menanam padi.", "ja": "昔の人々は稲作を始めました。", "audio": "audio/hist/h02.mp3"}, {"title": "クタイ王国", "body": "4世紀、カリマンタンに最古の王国が生まれた。", "id": "Kutai adalah kerajaan tertua di Indonesia.", "ja": "クタイはインドネシア最古の王国です。", "audio": "audio/hist/h03.mp3"}, {"title": "タルマヌガラ", "body": "西ジャワのヒンドゥー王国。", "id": "Tarumanagara adalah kerajaan Hindu di Jawa Barat.", "ja": "タルマヌガラは西ジャワのヒンドゥー王国です。", "audio": "audio/hist/h04.mp3"}, {"title": "スリウィジャヤ", "body": "7世紀、スマトラの海洋交易帝国。", "id": "Sriwijaya adalah kerajaan maritim yang besar.", "ja": "スリウィジャヤは大きな海洋王国でした。", "audio": "audio/hist/h05.mp3"}, {"title": "ボロブドゥール", "body": "8〜9世紀、世界最大級の仏教寺院。", "id": "Borobudur adalah candi Buddha terbesar di dunia.", "ja": "ボロブドゥールは世界最大の仏教寺院です。", "audio": "audio/hist/h06.mp3"}, {"title": "プランバナン", "body": "壮大なヒンドゥー寺院群。", "id": "Prambanan adalah candi Hindu yang megah.", "ja": "プランバナンは壮大なヒンドゥー寺院です。", "audio": "audio/hist/h07.mp3"}, {"title": "クディリ王国", "body": "東ジャワで文学が栄えた。", "id": "Kerajaan Kediri terkenal dengan karya sastra.", "ja": "クディリ王国は文学で有名です。", "audio": "audio/hist/h08.mp3"}, {"title": "シンガサリ", "body": "東ジャワの強国。", "id": "Singhasari adalah kerajaan kuat di Jawa Timur.", "ja": "シンガサリは東ジャワの強い王国でした。", "audio": "audio/hist/h09.mp3"}, {"title": "マジャパヒト", "body": "14世紀、群島を統一した黄金時代。", "id": "Majapahit adalah kerajaan terbesar dalam sejarah.", "ja": "マジャパヒトは歴史上最大の王国です。", "audio": "audio/hist/h10.mp3"}, {"title": "イスラムの伝来", "body": "商人を通じてイスラム教が広まった。", "id": "Islam masuk ke Indonesia lewat pedagang.", "ja": "イスラム教は商人を通じて伝わりました。", "audio": "audio/hist/h11.mp3"}, {"title": "ワリ・ソンゴ", "body": "9人の聖者がジャワにイスラムを広めた。", "id": "Wali Songo menyebarkan Islam di Jawa.", "ja": "ワリソンゴがジャワにイスラムを広めました。", "audio": "audio/hist/h12.mp3"}, {"title": "ドマク王国", "body": "ジャワ初のイスラム王国。", "id": "Demak adalah kerajaan Islam pertama di Jawa.", "ja": "ドマクはジャワ初のイスラム王国です。", "audio": "audio/hist/h13.mp3"}, {"title": "アチェ王国", "body": "スマトラ北端の強いイスラム王国。", "id": "Aceh adalah kesultanan yang kuat di Sumatra.", "ja": "アチェはスマトラの強いスルタン国でした。", "audio": "audio/hist/h14.mp3"}, {"title": "マタラム王国", "body": "スルタン・アグンが最盛期を築いた。", "id": "Sultan Agung adalah raja besar Mataram.", "ja": "スルタン・アグンはマタラムの偉大な王です。", "audio": "audio/hist/h15.mp3"}, {"title": "香辛料を求めて", "body": "ヨーロッパ人は香辛料を求めて来た。", "id": "Orang Eropa datang mencari rempah-rempah.", "ja": "ヨーロッパ人は香辛料を求めて来ました。", "audio": "audio/hist/h16.mp3"}, {"title": "ポルトガル来航", "body": "1512年、マルク諸島に到達。", "id": "Portugis tiba di Kepulauan Maluku.", "ja": "ポルトガル人はマルク諸島に到達しました。", "audio": "audio/hist/h17.mp3"}, {"title": "VOC設立", "body": "1602年、オランダ東インド会社が交易を独占。", "id": "VOC adalah perusahaan dagang Belanda.", "ja": "VOCはオランダの貿易会社です。", "audio": "audio/hist/h18.mp3"}, {"title": "バタヴィア建設", "body": "1619年、VOCがジャカルタを拠点にした。", "id": "Belanda membangun kota Batavia, sekarang Jakarta.", "ja": "オランダはバタヴィア(現ジャカルタ)を築きました。", "audio": "audio/hist/h19.mp3"}, {"title": "貿易の独占", "body": "VOCが香辛料貿易を支配した。", "id": "VOC menguasai perdagangan rempah.", "ja": "VOCは香辛料貿易を支配しました。", "audio": "audio/hist/h20.mp3"}, {"title": "植民地の拡大", "body": "オランダは各地の王国を従えた。", "id": "Belanda menjajah banyak kerajaan.", "ja": "オランダは多くの王国を植民地化しました。", "audio": "audio/hist/h21.mp3"}, {"title": "ディポネゴロ戦争", "body": "1825〜30年、大きな抵抗運動。", "id": "Pangeran Diponegoro melawan Belanda.", "ja": "ディポネゴロ王子はオランダと戦いました。", "audio": "audio/hist/h22.mp3"}, {"title": "強制栽培制度", "body": "農民は作物の栽培を強制された。", "id": "Rakyat dipaksa menanam untuk Belanda.", "ja": "民衆はオランダのため栽培を強制されました。", "audio": "audio/hist/h23.mp3"}, {"title": "オランダ領東インド", "body": "政府による長い植民地支配。", "id": "Indonesia dijajah Belanda selama ratusan tahun.", "ja": "インドネシアは何百年もオランダに支配されました。", "audio": "audio/hist/h24.mp3"}, {"title": "倫理政策", "body": "教育や灌漑が一部で進んだ。", "id": "Belanda mulai membangun sekolah dan irigasi.", "ja": "オランダは学校や灌漑を作り始めました。", "audio": "audio/hist/h25.mp3"}, {"title": "カルティニ", "body": "女性教育の先駆者。", "id": "Kartini memperjuangkan pendidikan perempuan.", "ja": "カルティニは女性教育のために闘いました。", "audio": "audio/hist/h26.mp3"}, {"title": "民族覚醒", "body": "1908年、ブディ・ウトモが誕生。", "id": "Budi Utomo adalah awal kebangkitan nasional.", "ja": "ブディ・ウトモは民族覚醒の始まりです。", "audio": "audio/hist/h27.mp3"}, {"title": "大衆運動", "body": "サレカット・イスラムが広がった。", "id": "Sarekat Islam adalah gerakan rakyat.", "ja": "サレカット・イスラムは大衆運動です。", "audio": "audio/hist/h28.mp3"}, {"title": "青年の誓い", "body": "1928年、一つの言語・国・民族を誓った。", "id": "Sumpah Pemuda menyatukan bahasa Indonesia.", "ja": "青年の誓いはインドネシア語を統一しました。", "audio": "audio/hist/h29.mp3"}, {"title": "スカルノ", "body": "独立運動の指導者。", "id": "Sukarno adalah pemimpin kemerdekaan.", "ja": "スカルノは独立の指導者です。", "audio": "audio/hist/h30.mp3"}, {"title": "日本軍政", "body": "1942〜45年、日本が占領した。", "id": "Jepang menduduki Indonesia selama tiga tahun.", "ja": "日本は3年間インドネシアを占領しました。", "audio": "audio/hist/h31.mp3"}, {"title": "独立への準備", "body": "独立に向けた委員会が作られた。", "id": "Rakyat bersiap untuk merdeka.", "ja": "人々は独立の準備をしました。", "audio": "audio/hist/h32.mp3"}, {"title": "パンチャシラ", "body": "建国五原則が定められた。", "id": "Pancasila adalah dasar negara Indonesia.", "ja": "パンチャシラはインドネシアの建国理念です。", "audio": "audio/hist/h33.mp3"}, {"title": "独立宣言", "body": "1945年8月17日、独立を宣言。", "id": "Indonesia merdeka pada 17 Agustus 1945.", "ja": "インドネシアは1945年8月17日に独立しました。", "audio": "audio/hist/h34.mp3"}, {"title": "独立戦争", "body": "オランダと4年間戦った。", "id": "Rakyat berjuang melawan penjajah.", "ja": "人々は植民者と戦いました。", "audio": "audio/hist/h35.mp3"}, {"title": "英雄の日", "body": "スラバヤの戦い(11月10日)。", "id": "Hari Pahlawan diperingati setiap 10 November.", "ja": "英雄の日は毎年11月10日に記念されます。", "audio": "audio/hist/h36.mp3"}, {"title": "主権移譲", "body": "1949年、独立が国際的に認められた。", "id": "Belanda akhirnya mengakui kemerdekaan Indonesia.", "ja": "オランダはついに独立を承認しました。", "audio": "audio/hist/h37.mp3"}, {"title": "建国期", "body": "独立したばかりの国を導いた。", "id": "Sukarno memimpin negara yang baru merdeka.", "ja": "スカルノは独立したばかりの国を率いました。", "audio": "audio/hist/h38.mp3"}, {"title": "バンドン会議", "body": "1955年、アジア・アフリカ会議を開催。", "id": "Konferensi Asia-Afrika diadakan di Bandung.", "ja": "アジア・アフリカ会議がバンドンで開かれました。", "audio": "audio/hist/h39.mp3"}, {"title": "島々の統一", "body": "広い群島を一つの国にまとめた。", "id": "Indonesia menyatukan ribuan pulau.", "ja": "インドネシアは数千の島を統一しました。", "audio": "audio/hist/h40.mp3"}, {"title": "1965年の動乱", "body": "大きな政治的事件が起きた。", "id": "Tahun 1965 terjadi peristiwa politik besar.", "ja": "1965年に大きな政治的事件が起きました。", "audio": "audio/hist/h41.mp3"}, {"title": "スハルト新秩序", "body": "32年間の長期政権。", "id": "Suharto memimpin selama tiga puluh dua tahun.", "ja": "スハルトは32年間統治しました。", "audio": "audio/hist/h42.mp3"}, {"title": "経済開発", "body": "開発が進み経済が成長した。", "id": "Ekonomi Indonesia tumbuh pada masa itu.", "ja": "その時代に経済が成長しました。", "audio": "audio/hist/h43.mp3"}, {"title": "多様性の中の統一", "body": "国の標語を掲げる。", "id": "Semboyan negara adalah Bhinneka Tunggal Ika.", "ja": "国の標語は「多様性の中の統一」です。", "audio": "audio/hist/h44.mp3"}, {"title": "通貨危機", "body": "1997〜98年、経済が混乱した。", "id": "Tahun 1998 terjadi krisis ekonomi.", "ja": "1998年に経済危機が起きました。", "audio": "audio/hist/h45.mp3"}, {"title": "レフォルマシ", "body": "1998年、民主化が始まった。", "id": "Reformasi membawa demokrasi ke Indonesia.", "ja": "レフォルマシは民主主義をもたらしました。", "audio": "audio/hist/h46.mp3"}, {"title": "直接選挙", "body": "国民が大統領を直接選ぶように。", "id": "Rakyat memilih presiden secara langsung.", "ja": "国民が大統領を直接選びます。", "audio": "audio/hist/h47.mp3"}, {"title": "津波と復興", "body": "2004年、スマトラ沖地震・津波。", "id": "Tahun 2004 terjadi gempa dan tsunami di Aceh.", "ja": "2004年アチェで地震と津波が起きました。", "audio": "audio/hist/h48.mp3"}, {"title": "現代インドネシア", "body": "世界最大の島嶼・多民族国家。", "id": "Indonesia kini negara kepulauan terbesar di dunia.", "ja": "インドネシアは今、世界最大の島国です。", "audio": "audio/hist/h49.mp3"}];
window.GEO = [{"emoji": "🕌", "region": "スマトラ", "name": "アチェ州", "body": "スマトラ島最北端。イスラム文化が根強く「メッカのベランダ」と呼ばれる。", "id": "Aceh terkenal dengan kopi Gayo, dan ibu kotanya adalah Banda Aceh.", "ja": "アチェはガヨコーヒーで有名で、州都はバンダ・アチェです。", "audio": "audio/geo/geo00.mp3"}, {"emoji": "🌋", "region": "スマトラ", "name": "北スマトラ州", "body": "トバ湖やバタック文化で有名。州都メダンは国内第3の都市。", "id": "Di Sumatera Utara ada Danau Toba yang indah, dengan ibu kota Medan.", "ja": "北スマトラには美しいトバ湖があり、州都はメダンです。", "audio": "audio/geo/geo01.mp3"}, {"emoji": "🍛", "region": "スマトラ", "name": "西スマトラ州", "body": "ミナンカバウ文化の地。パダン料理(ルンダン)の発祥地。", "id": "Rendang yang terkenal berasal dari Sumatera Barat, ibu kotanya Padang.", "ja": "有名なルンダンは西スマトラ発祥で、州都はパダンです。", "audio": "audio/geo/geo02.mp3"}, {"emoji": "🛢️", "region": "スマトラ", "name": "リアウ州", "body": "石油とパーム油の産地。マレー文化圏に属する。", "id": "Riau kaya akan minyak bumi, dan ibu kotanya adalah Pekanbaru.", "ja": "リアウは石油が豊富で、州都はプカンバルです。", "audio": "audio/geo/geo03.mp3"}, {"emoji": "🏝️", "region": "スマトラ", "name": "リアウ諸島州", "body": "シンガポール対岸のバタム島を擁する島嶼の州。", "id": "Kepulauan Riau dekat dengan Singapura, ibu kotanya Tanjung Pinang.", "ja": "リアウ諸島はシンガポールに近く、州都はタンジュン・ピナンです。", "audio": "audio/geo/geo04.mp3"}, {"emoji": "🏞️", "region": "スマトラ", "name": "ジャンビ州", "body": "スマトラ最高峰クリンチ山がそびえる。", "id": "Jambi punya Gunung Kerinci, gunung tertinggi di Sumatera, ibu kotanya Kota Jambi.", "ja": "ジャンビにはスマトラ最高峰クリンチ山があり、州都はジャンビ市です。", "audio": "audio/geo/geo05.mp3"}, {"emoji": "🍢", "region": "スマトラ", "name": "南スマトラ州", "body": "かつてのシュリーヴィジャヤ王国の中心。名物はプンペック。", "id": "Pempek adalah makanan khas Palembang, ibu kota Sumatera Selatan.", "ja": "プンペックはパレンバンの名物料理で、南スマトラ州の州都です。", "audio": "audio/geo/geo06.mp3"}, {"emoji": "🏖️", "region": "スマトラ", "name": "バンカ・ブリトゥン州", "body": "錫(すず)の島と白砂ビーチで知られる。", "id": "Bangka Belitung terkenal dengan tambang timah, ibu kotanya Pangkalpinang.", "ja": "バンカ・ブリトゥンは錫鉱山で有名で、州都はパンカルピナンです。", "audio": "audio/geo/geo07.mp3"}, {"emoji": "🌺", "region": "スマトラ", "name": "ブンクル州", "body": "世界最大の花ラフレシアで有名。", "id": "Bunga Rafflesia yang raksasa tumbuh di Bengkulu, ibu kotanya Kota Bengkulu.", "ja": "巨大なラフレシアの花がブンクルに咲き、州都はブンクル市です。", "audio": "audio/geo/geo08.mp3"}, {"emoji": "🐘", "region": "スマトラ", "name": "ランプン州", "body": "ジャワへの玄関口。ゾウ保護区がある。", "id": "Lampung punya taman gajah yang terkenal, dengan ibu kota Bandar Lampung.", "ja": "ランプンには有名なゾウ保護区があり、州都はバンダール・ランプンです。", "audio": "audio/geo/geo09.mp3"}, {"emoji": "🏙️", "region": "ジャワ", "name": "ジャカルタ首都特別州", "body": "人口約1000万の首都。", "id": "Jakarta adalah ibu kota negara dan kota terbesar di Indonesia.", "ja": "ジャカルタは首都でインドネシア最大の都市です。", "audio": "audio/geo/geo10.mp3"}, {"emoji": "🏔️", "region": "ジャワ", "name": "西ジャワ州", "body": "人口最多の州。スンダ文化。", "id": "Bandung di Jawa Barat terkenal dengan udara sejuk dan wisata belanja.", "ja": "西ジャワのバンドンは涼しい気候とショッピングで有名です。", "audio": "audio/geo/geo11.mp3"}, {"emoji": "🌾", "region": "ジャワ", "name": "バンテン州", "body": "ジャワ島西端。先住民バドゥイ族が暮らす。", "id": "Suku Baduy tinggal di Banten, provinsi dengan ibu kota Serang.", "ja": "バドゥイ族はバンテンに住み、州都はスランです。", "audio": "audio/geo/geo12.mp3"}, {"emoji": "🛕", "region": "ジャワ", "name": "中部ジャワ州", "body": "ジャワ文化の中心。世界遺産ボロブドゥールを擁する。", "id": "Candi Borobudur ada di Jawa Tengah, yang ibu kotanya Semarang.", "ja": "ボロブドゥール寺院は中部ジャワにあり、州都はスマランです。", "audio": "audio/geo/geo13.mp3"}, {"emoji": "👑", "region": "ジャワ", "name": "ジョグジャカルタ特別州", "body": "王家が統治する特別州。芸術と学問の都。", "id": "Yogyakarta terkenal dengan Keraton dan seni batik.", "ja": "ジョグジャカルタは王宮とバティック工芸で有名です。", "audio": "audio/geo/geo14.mp3"}, {"emoji": "🌋", "region": "ジャワ", "name": "東ジャワ州", "body": "ブロモ山で有名。州都スラバヤは国内第2の都市。", "id": "Surabaya adalah kota terbesar kedua, ibu kota Jawa Timur.", "ja": "スラバヤは第2の都市で、東ジャワ州の州都です。", "audio": "audio/geo/geo15.mp3"}, {"emoji": "🛕", "region": "バリ・ヌサトゥンガラ", "name": "バリ州", "body": "ヒンドゥー文化の島。世界的な観光地。", "id": "Bali terkenal dengan pura, tarian, dan pantainya, ibu kotanya Denpasar.", "ja": "バリは寺院・踊り・ビーチで有名で、州都はデンパサールです。", "audio": "audio/geo/geo16.mp3"}, {"emoji": "⛰️", "region": "バリ・ヌサトゥンガラ", "name": "西ヌサ・トゥンガラ州", "body": "ロンボク島とスンバワ島。", "id": "Gunung Rinjani ada di Nusa Tenggara Barat, ibu kotanya Mataram.", "ja": "リンジャニ山は西ヌサ・トゥンガラにあり、州都はマタラムです。", "audio": "audio/geo/geo17.mp3"}, {"emoji": "🦎", "region": "バリ・ヌサトゥンガラ", "name": "東ヌサ・トゥンガラ州", "body": "フローレス島などからなる。", "id": "Komodo hidup di Nusa Tenggara Timur, provinsi dengan ibu kota Kupang.", "ja": "コモドドラゴンは東ヌサ・トゥンガラに生息し、州都はクパンです。", "audio": "audio/geo/geo18.mp3"}, {"emoji": "🌐", "region": "カリマンタン", "name": "西カリマンタン州", "body": "赤道直下。", "id": "Kota Pontianak dilewati garis khatulistiwa, ibu kota Kalimantan Barat.", "ja": "ポンティアナックは赤道が通り、西カリマンタン州の州都です。", "audio": "audio/geo/geo19.mp3"}, {"emoji": "🦧", "region": "カリマンタン", "name": "中部カリマンタン州", "body": "熱帯雨林とオランウータンの生息地。", "id": "Kalimantan Tengah adalah rumah bagi orang utan, ibu kotanya Palangka Raya.", "ja": "中部カリマンタンはオランウータンの生息地で、州都はパランカラヤです。", "audio": "audio/geo/geo20.mp3"}, {"emoji": "🛶", "region": "カリマンタン", "name": "南カリマンタン州", "body": "水上市場で有名。", "id": "Kalimantan Selatan terkenal dengan pasar terapung, ibu kotanya Banjarbaru.", "ja": "南カリマンタンは水上市場で有名で、州都はバンジャルバルです。", "audio": "audio/geo/geo21.mp3"}, {"emoji": "🏗️", "region": "カリマンタン", "name": "東カリマンタン州", "body": "新首都ヌサンタラ(IKN)の建設地。", "id": "Ibu kota baru Indonesia, Nusantara, dibangun di Kalimantan Timur.", "ja": "インドネシアの新首都ヌサンタラは東カリマンタンに建設中です。", "audio": "audio/geo/geo22.mp3"}, {"emoji": "🌲", "region": "カリマンタン", "name": "北カリマンタン州", "body": "マレーシアと国境を接する最北の新州。", "id": "Kalimantan Utara berbatasan dengan Malaysia, ibu kotanya Tanjung Selor.", "ja": "北カリマンタンはマレーシアと国境を接し、州都はタンジュン・スロールです。", "audio": "audio/geo/geo23.mp3"}, {"emoji": "🐠", "region": "スラウェシ", "name": "北スラウェシ州", "body": "キリスト教徒が多い地域。", "id": "Taman laut Bunaken ada di Sulawesi Utara, ibu kotanya Manado.", "ja": "海洋公園ブナケンは北スラウェシにあり、州都はマナドです。", "audio": "audio/geo/geo24.mp3"}, {"emoji": "🌽", "region": "スラウェシ", "name": "ゴロンタロ州", "body": "トウモロコシの産地。", "id": "Gorontalo terkenal sebagai daerah penghasil jagung.", "ja": "ゴロンタロはトウモロコシの産地として有名です。", "audio": "audio/geo/geo25.mp3"}, {"emoji": "🗿", "region": "スラウェシ", "name": "中部スラウェシ州", "body": "ロレ・リンドゥ国立公園の巨石遺跡。", "id": "Sulawesi Tengah punya situs megalit kuno di Lembah Bada, ibu kotanya Palu.", "ja": "中部スラウェシのバダ渓谷には古代の巨石遺跡があり、州都はパルです。", "audio": "audio/geo/geo26.mp3"}, {"emoji": "🌊", "region": "スラウェシ", "name": "西スラウェシ州", "body": "2004年に分立した新しい州。", "id": "Sulawesi Barat adalah provinsi muda dengan ibu kota Mamuju.", "ja": "西スラウェシは新しい州で、州都はママジュです。", "audio": "audio/geo/geo27.mp3"}, {"emoji": "⛵", "region": "スラウェシ", "name": "南スラウェシ州", "body": "海洋民ブギス・マカッサルの地。", "id": "Makassar terkenal dengan kapal pinisi dan kuliner Coto.", "ja": "マカッサルは帆船ピニシと料理チョトで有名です。", "audio": "audio/geo/geo28.mp3"}, {"emoji": "⛏️", "region": "スラウェシ", "name": "南東スラウェシ州", "body": "ワカトビの海とニッケルの産地。", "id": "Sulawesi Tenggara punya laut Wakatobi yang indah, ibu kotanya Kendari.", "ja": "南東スラウェシには美しいワカトビの海があり、州都はケンダリです。", "audio": "audio/geo/geo29.mp3"}, {"emoji": "🌶️", "region": "マルク", "name": "マルク州", "body": "かつての「香料諸島」。", "id": "Maluku dulu disebut Kepulauan Rempah, ibu kotanya Ambon.", "ja": "マルクはかつて香料諸島と呼ばれ、州都はアンボンです。", "audio": "audio/geo/geo30.mp3"}, {"emoji": "🌋", "region": "マルク", "name": "北マルク州", "body": "クローブの原産地。", "id": "Cengkih berasal dari Maluku Utara, ibu kotanya Sofifi.", "ja": "クローブは北マルク原産で、州都はソフィフィです。", "audio": "audio/geo/geo31.mp3"}, {"emoji": "🏔️", "region": "パプア", "name": "パプア州", "body": "ニューギニア島の北東部。", "id": "Papua punya Danau Sentani yang indah, dekat ibu kota Jayapura.", "ja": "パプアには美しいセンタニ湖があり、州都ジャヤプラの近くです。", "audio": "audio/geo/geo32.mp3"}, {"emoji": "🐦", "region": "パプア", "name": "西パプア州", "body": "「鳥の頭半島」に位置する。", "id": "Papua Barat berada di Semenanjung Kepala Burung, ibu kotanya Manokwari.", "ja": "西パプアは鳥の頭半島にあり、州都はマノクワリです。", "audio": "audio/geo/geo33.mp3"}, {"emoji": "🌅", "region": "パプア", "name": "南パプア州", "body": "2022年新設。最東端の街。", "id": "Merauke adalah kota paling timur di Indonesia, ibu kota Papua Selatan.", "ja": "メラウケはインドネシア最東端の街で、南パプア州の州都です。", "audio": "audio/geo/geo34.mp3"}, {"emoji": "🏔️", "region": "パプア", "name": "中部パプア州", "body": "2022年新設。氷河を頂くプンチャック・ジャヤ。", "id": "Puncak Jaya yang bersalju ada di Papua Tengah, ibu kotanya Nabire.", "ja": "雪を頂くプンチャック・ジャヤは中部パプアにあり、州都はナビレです。", "audio": "audio/geo/geo35.mp3"}, {"emoji": "🏞️", "region": "パプア", "name": "山岳パプア州", "body": "2022年新設。海に面しない唯一の州。", "id": "Lembah Baliem yang terkenal ada di Papua Pegunungan, ibu kotanya Wamena.", "ja": "有名なバリエム渓谷は山岳パプアにあり、州都はワメナです。", "audio": "audio/geo/geo36.mp3"}, {"emoji": "🐠", "region": "パプア", "name": "南西パプア州", "body": "2022年新設。ラジャ・アンパットの玄関口。", "id": "Sorong adalah pintu masuk ke Raja Ampat, ibu kota Papua Barat Daya.", "ja": "ソロンはラジャ・アンパットへの玄関口で、南西パプア州の州都です。", "audio": "audio/geo/geo37.mp3"}, {"emoji": "🌋", "region": "スマトラ", "name": "トバ湖", "body": "北スマトラの巨大カルデラ湖。中央のサモシール島にバタック文化。", "id": "Danau Toba terbentuk dari letusan gunung berapi raksasa.", "ja": "トバ湖は巨大火山の噴火でできました。", "audio": "audio/geo/geo38.mp3"}, {"emoji": "🕰️", "region": "スマトラ", "name": "ジャム・ガダン", "body": "西スマトラ・ブキティンギのシンボル。", "id": "Jam Gadang adalah menara jam bergaya Minangkabau di Bukittinggi.", "ja": "ジャム・ガダンはブキティンギのミナンカバウ様式の時計塔です。", "audio": "audio/geo/geo39.mp3"}, {"emoji": "🏖️", "region": "スマトラ", "name": "ブリトゥン島", "body": "映画『虹の兵士たち』の舞台。", "id": "Pantai Belitung punya batu granit raksasa dan pasir putih.", "ja": "ブリトゥンの浜には巨大な花崗岩と白い砂があります。", "audio": "audio/geo/geo40.mp3"}, {"emoji": "🛕", "region": "ジャワ", "name": "ボロブドゥール", "body": "9世紀に築かれた世界遺産。", "id": "Borobudur adalah candi Buddha terbesar di dunia.", "ja": "ボロブドゥールは世界最大の仏教寺院です。", "audio": "audio/geo/geo41.mp3"}, {"emoji": "🌋", "region": "ジャワ", "name": "ブロモ山", "body": "東ジャワの活火山。", "id": "Wisatawan datang ke Gunung Bromo untuk melihat matahari terbit.", "ja": "観光客は日の出を見にブロモ山へ来ます。", "audio": "audio/geo/geo42.mp3"}, {"emoji": "🔥", "region": "ジャワ", "name": "イジェン火口", "body": "東ジャワ。青い炎で知られる。", "id": "Kawah Ijen terkenal dengan api biru pada malam hari.", "ja": "イジェン火口は夜の青い炎で有名です。", "audio": "audio/geo/geo43.mp3"}, {"emoji": "🎨", "region": "バリ・ヌサトゥンガラ", "name": "ウブド", "body": "バリ島中部。棚田と芸術の村。", "id": "Ubud adalah pusat seni, tari, dan sawah terasering di Bali.", "ja": "ウブドはバリの芸術・踊り・棚田の中心です。", "audio": "audio/geo/geo44.mp3"}, {"emoji": "🦎", "region": "バリ・ヌサトゥンガラ", "name": "ラブアン・バジョ", "body": "コモド島への玄関口。", "id": "Dari Labuan Bajo, kita bisa pergi melihat komodo.", "ja": "ラブアン・バジョからコモドドラゴンを見に行けます。", "audio": "audio/geo/geo45.mp3"}, {"emoji": "🏚️", "region": "スラウェシ", "name": "タナ・トラジャ", "body": "舟形の家トンコナンと独特の葬送儀礼。", "id": "Di Tana Toraja ada rumah adat Tongkonan dan upacara pemakaman yang unik.", "ja": "タナ・トラジャには伝統家屋トンコナンと独特の葬儀があります。", "audio": "audio/geo/geo46.mp3"}, {"emoji": "🐠", "region": "スラウェシ", "name": "ブナケン", "body": "マナド沖の海洋国立公園。", "id": "Bunaken adalah surga bagi para penyelam.", "ja": "ブナケンはダイバーの楽園です。", "audio": "audio/geo/geo47.mp3"}, {"emoji": "🤿", "region": "スラウェシ", "name": "ワカトビ", "body": "南東スラウェシの珊瑚礁。", "id": "Wakatobi punya terumbu karang yang paling indah di dunia.", "ja": "ワカトビには世界一美しい珊瑚礁があります。", "audio": "audio/geo/geo48.mp3"}, {"emoji": "🐠", "region": "パプア", "name": "ラジャ・アンパット", "body": "西パプアの秘境。", "id": "Raja Ampat memiliki keanekaragaman laut terkaya di dunia.", "ja": "ラジャ・アンパットは世界一豊かな海の生物多様性を誇ります。", "audio": "audio/geo/geo49.mp3"}];
window.DAILY = [{"title": "MRT ジャカルタ", "body": "市内を南北に結ぶ新しい地下鉄。渋滞知らずで通勤に人気。", "id": "MRT Jakarta cepat dan bebas macet.", "ja": "ジャカルタのMRTは速くて渋滞がありません。", "emoji": "🚇", "audio": "audio/daily/d00.mp3"}, {"title": "トランスジャカルタ", "body": "専用レーンを走る連節バス（busway）。安くて路線が広い。", "id": "TransJakarta adalah bus dengan jalur khusus.", "ja": "トランスジャカルタは専用レーンのバスです。", "emoji": "🚌", "audio": "audio/daily/d01.mp3"}, {"title": "KRL 近郊電車", "body": "首都圏を走る通勤電車。安くて庶民の足。", "id": "KRL adalah kereta untuk komuter di Jakarta.", "ja": "KRLはジャカルタの通勤電車です。", "emoji": "🚆", "audio": "audio/daily/d02.mp3"}, {"title": "オジェック・オンライン", "body": "GojekやGrabのバイクタクシー。アプリで呼べる。", "id": "Ojek online bisa dipesan lewat aplikasi.", "ja": "オジェックオンラインはアプリで呼べます。", "emoji": "🛵", "audio": "audio/daily/d03.mp3"}, {"title": "Gojek / Grab", "body": "配車・配達・決済まで何でもできるアプリ。", "id": "Gojek dan Grab sangat populer di Indonesia.", "ja": "GojekとGrabはインドネシアでとても人気です。", "emoji": "📱", "audio": "audio/daily/d04.mp3"}, {"title": "アンコット", "body": "決まった路線を走る乗合ミニバス。手を挙げて止める。", "id": "Angkot adalah angkutan umum kecil.", "ja": "アンコットは小さな乗合バスです。", "emoji": "🚐", "audio": "audio/daily/d05.mp3"}, {"title": "バジャイ", "body": "オレンジ色の三輪タクシー。近距離の移動に。", "id": "Bajaj adalah kendaraan roda tiga.", "ja": "バジャイは三輪の乗り物です。", "emoji": "🛺", "audio": "audio/daily/d06.mp3"}, {"title": "Indomaret / Alfamart", "body": "街中いたる所にあるミニマート。24時間の店も多い。", "id": "Indomaret ada di mana-mana di Jakarta.", "ja": "Indomaretはジャカルタのいたる所にあります。", "emoji": "🏪", "audio": "audio/daily/d07.mp3"}, {"title": "ワルン", "body": "個人経営の小さな店や食堂。生活に欠かせない。", "id": "Warung adalah toko kecil milik warga.", "ja": "ワルンは住民が営む小さな店です。", "emoji": "🏬", "audio": "audio/daily/d08.mp3"}, {"title": "ワルテグ", "body": "安くておかずを選べる大衆食堂。", "id": "Warteg menjual makanan murah dan enak.", "ja": "ワルテグは安くて美味しい料理を売ります。", "emoji": "🍚", "audio": "audio/daily/d09.mp3"}, {"title": "カキリマ", "body": "屋台や移動販売のこと。歩道で商売する。", "id": "Kaki lima menjual makanan di pinggir jalan.", "ja": "カキリマは道端で食べ物を売ります。", "emoji": "🛒", "audio": "audio/daily/d10.mp3"}, {"title": "ゴレンガン", "body": "バナナや豆腐などの揚げ物。おやつの定番。", "id": "Gorengan adalah camilan yang digoreng.", "ja": "ゴレンガンは揚げたおやつです。", "emoji": "🍤", "audio": "audio/daily/d11.mp3"}, {"title": "バッソ", "body": "肉団子入りのスープ。屋台の人気メニュー。", "id": "Bakso adalah bola daging dengan kuah.", "ja": "バッソはスープ入りの肉団子です。", "emoji": "🍜", "audio": "audio/daily/d12.mp3"}, {"title": "ミー・アヤム", "body": "鶏肉をのせた汁なし・汁ありの麺。", "id": "Mie ayam adalah mie dengan ayam.", "ja": "ミーアヤムは鶏肉入りの麺です。", "emoji": "🍲", "audio": "audio/daily/d13.mp3"}, {"title": "ナシ・パダン", "body": "西スマトラ発の料理。皿を並べて選ぶ。", "id": "Nasi Padang terkenal dengan rasa pedas.", "ja": "ナシパダンは辛さで有名です。", "emoji": "🍛", "audio": "audio/daily/d14.mp3"}, {"title": "マルタバ", "body": "甘い生地や卵入りの人気ストリートフード。", "id": "Martabak ada yang manis dan asin.", "ja": "マルタバには甘いものと塩味があります。", "emoji": "🥮", "audio": "audio/daily/d15.mp3"}, {"title": "エス・テ・マニス", "body": "甘い冷たい紅茶。食事の定番ドリンク。", "id": "Es teh manis adalah minuman favorit.", "ja": "エステマニスは人気の飲み物です。", "emoji": "🧉", "audio": "audio/daily/d16.mp3"}, {"title": "コピ・トゥブルッ", "body": "粉をそのまま入れる濃いコーヒー。", "id": "Kopi tubruk adalah kopi khas Indonesia.", "ja": "コピトゥブルックはインドネシア独特のコーヒーです。", "emoji": "☕", "audio": "audio/daily/d17.mp3"}, {"title": "ガロン（飲料水）", "body": "家庭で使う大きな水ボトル。配達もある。", "id": "Galon air minum diantar ke rumah.", "ja": "飲料水のガロンは家まで配達されます。", "emoji": "💧", "audio": "audio/daily/d18.mp3"}, {"title": "トゥカン・サユール", "body": "野菜や食材を売り歩く行商人。", "id": "Tukang sayur keliling menjual sayuran.", "ja": "トゥカンサユールは野菜を売り歩きます。", "emoji": "🥬", "audio": "audio/daily/d19.mp3"}, {"title": "ワルン・マドゥラ", "body": "24時間開く便利な個人商店。", "id": "Warung Madura buka 24 jam.", "ja": "マドゥラのワルンは24時間営業です。", "emoji": "🕛", "audio": "audio/daily/d20.mp3"}, {"title": "QRIS", "body": "QRコードで払える統一電子決済。", "id": "QRIS memudahkan pembayaran digital.", "ja": "QRISは電子決済を簡単にします。", "emoji": "🔳", "audio": "audio/daily/d21.mp3"}, {"title": "プルサ（携帯チャージ）", "body": "プリペイド携帯の通信料。店でチャージ。", "id": "Pulsa dibeli untuk mengisi telepon.", "ja": "プルサは携帯をチャージするために買います。", "emoji": "📶", "audio": "audio/daily/d22.mp3"}, {"title": "トークン電気", "body": "プリペイド式電気。番号を入力して使う。", "id": "Token listrik dibeli sebelum habis.", "ja": "電気トークンは無くなる前に買います。", "emoji": "🔌", "audio": "audio/daily/d23.mp3"}, {"title": "駐車係（Pak Ogah）", "body": "道端で駐車や車の誘導を手伝う人。", "id": "Juru parkir membantu memarkir mobil.", "ja": "駐車係は車の駐車を手伝います。", "emoji": "🅿️", "audio": "audio/daily/d24.mp3"}, {"title": "マチェット（渋滞）", "body": "ジャカルタ名物のひどい交通渋滞。", "id": "Jakarta terkenal dengan macetnya.", "ja": "ジャカルタは渋滞で有名です。", "emoji": "🚗", "audio": "audio/daily/d25.mp3"}, {"title": "バンジール（洪水）", "body": "雨季に起こる冠水。生活の悩みの種。", "id": "Banjir sering terjadi saat musim hujan.", "ja": "洪水は雨季によく起こります。", "emoji": "🌧️", "audio": "audio/daily/d26.mp3"}, {"title": "ワルン・クロントン", "body": "日用品を売る昔ながらの雑貨店。", "id": "Warung kelontong menjual kebutuhan harian.", "ja": "雑貨店は日用品を売ります。", "emoji": "🧴", "audio": "audio/daily/d27.mp3"}, {"title": "サンダル・ジェピット", "body": "ビーチサンダル。普段履きの定番。", "id": "Sandal jepit dipakai sehari-hari.", "ja": "ビーチサンダルは日常的に履きます。", "emoji": "🩴", "audio": "audio/daily/d28.mp3"}, {"title": "トゥカン・チュクル", "body": "路上や小さな店の床屋。安く切れる。", "id": "Tukang cukur memotong rambut dengan murah.", "ja": "床屋は安く髪を切ります。", "emoji": "💈", "audio": "audio/daily/d29.mp3"}, {"title": "ランドリー・キロアン", "body": "重さで料金が決まる洗濯サービス。", "id": "Laundry kiloan dihitung per kilogram.", "ja": "キロ制ランドリーはキロ単位で計算します。", "emoji": "🧺", "audio": "audio/daily/d30.mp3"}, {"title": "コス（下宿）", "body": "学生や社会人が借りる一部屋の下宿。", "id": "Banyak perantau tinggal di kos.", "ja": "多くの上京者は下宿に住みます。", "emoji": "🏠", "audio": "audio/daily/d31.mp3"}, {"title": "モール", "body": "冷房の効いた大型ショッピングモール。", "id": "Mal adalah tempat belanja yang besar.", "ja": "モールは大きな買い物の場所です。", "emoji": "🏙️", "audio": "audio/daily/d32.mp3"}, {"title": "トゥカン・バッソ売り", "body": "鐘を鳴らして回るバッソの移動屋台。", "id": "Tukang bakso keliling naik gerobak.", "ja": "バッソ売りは屋台を押して回ります。", "emoji": "🔔", "audio": "audio/daily/d33.mp3"}, {"title": "エス・チェンドル", "body": "緑のゼリーとココナツミルクの冷たい甘味。", "id": "Es cendol segar dan manis.", "ja": "エスチェンドルは爽やかで甘いです。", "emoji": "🍧", "audio": "audio/daily/d34.mp3"}, {"title": "GoFood / GrabFood", "body": "アプリで頼むフードデリバリー。", "id": "GoFood mengantar makanan ke rumah.", "ja": "GoFoodは食べ物を家まで届けます。", "emoji": "🛍️", "audio": "audio/daily/d35.mp3"}, {"title": "e-Toll", "body": "高速道路のカード決済。現金は使えない。", "id": "e-Toll dipakai untuk bayar jalan tol.", "ja": "e-Tollは高速料金の支払いに使います。", "emoji": "🛣️", "audio": "audio/daily/d36.mp3"}, {"title": "ハルテ（バス停）", "body": "トランスジャカルタの高床式バス停。", "id": "Halte adalah tempat menunggu bus.", "ja": "ハルテはバスを待つ場所です。", "emoji": "🚏", "audio": "audio/daily/d37.mp3"}, {"title": "オンデル・オンデル", "body": "ベタウィの大きな人形。祭りや路上で見る。", "id": "Ondel-ondel adalah boneka khas Betawi.", "ja": "オンデルオンデルはベタウィの人形です。", "emoji": "🎎", "audio": "audio/daily/d38.mp3"}, {"title": "モナス", "body": "独立記念塔。ジャカルタの象徴。", "id": "Monas adalah simbol kota Jakarta.", "ja": "モナスはジャカルタの象徴です。", "emoji": "🗼", "audio": "audio/daily/d39.mp3"}, {"title": "カー・フリー・デー", "body": "日曜の朝、車を止めて歩ける通り。", "id": "Car Free Day diadakan setiap Minggu pagi.", "ja": "カーフリーデーは毎週日曜の朝に行われます。", "emoji": "🚶", "audio": "audio/daily/d40.mp3"}, {"title": "ワルコピ（Warkop）", "body": "おしゃべりできる庶民的なコーヒー店。", "id": "Warkop adalah tempat ngopi dan ngobrol.", "ja": "ワルコピはコーヒーとおしゃべりの場所です。", "emoji": "🫖", "audio": "audio/daily/d41.mp3"}, {"title": "タンバル・バン", "body": "路上のパンク修理屋。バイク社会の必需。", "id": "Tukang tambal ban memperbaiki ban bocor.", "ja": "タンバルバンはパンクを修理します。", "emoji": "🔧", "audio": "audio/daily/d42.mp3"}, {"title": "サテ", "body": "串焼き。夜に炭火の煙と香りが漂う。", "id": "Sate adalah daging tusuk yang dibakar.", "ja": "サテは焼いた串肉です。", "emoji": "🍢", "audio": "audio/daily/d43.mp3"}, {"title": "ガドガド", "body": "茹で野菜にピーナッツソースをかけた料理。", "id": "Gado-gado adalah salad saus kacang.", "ja": "ガドガドはピーナッツソースのサラダです。", "emoji": "🥗", "audio": "audio/daily/d44.mp3"}, {"title": "ベチャ", "body": "人力の三輪車。今も一部の街に残る。", "id": "Becak adalah kendaraan yang dikayuh.", "ja": "ベチャは漕いで進む乗り物です。", "emoji": "🚲", "audio": "audio/daily/d45.mp3"}, {"title": "プダガン・アスンガン", "body": "電車やバスで物を売る行商。", "id": "Pedagang asongan menjual di kendaraan.", "ja": "行商人は乗り物の中で売ります。", "emoji": "🧃", "audio": "audio/daily/d46.mp3"}, {"title": "ハジャタン（近所の祝い事）", "body": "結婚式などご近所総出の催し。", "id": "Hajatan adalah acara warga kampung.", "ja": "ハジャタンは村人の催しです。", "emoji": "🎉", "audio": "audio/daily/d47.mp3"}, {"title": "サトゥパム（警備員）", "body": "建物や住宅街を守る警備員。", "id": "Satpam menjaga keamanan gedung.", "ja": "サトゥパムは建物の安全を守ります。", "emoji": "👮", "audio": "audio/daily/d48.mp3"}, {"title": "ゴジェック・ヘルメット", "body": "緑のジャケットとヘルメットが街の風景。", "id": "Driver ojol memakai jaket hijau.", "ja": "オジョルの運転手は緑の上着を着ます。", "emoji": "🪖", "audio": "audio/daily/d49.mp3"}];
window.CULTURE = [{"title": "あいさつの基本", "body": "一日の時間帯であいさつが変わります（pagi/siang/sore/malam）。", "id": "Selamat pagi, apa kabar?", "ja": "おはよう、元気？", "audio": "audio/cult/c00.mp3"}, {"title": "お礼と返し", "body": "「ありがとう」には「どういたしまして」で返します。", "id": "Terima kasih. Sama-sama.", "ja": "ありがとう。どういたしまして。", "audio": "audio/cult/c01.mp3"}, {"title": "握手のマナー", "body": "握手のあと手を胸に当てると丁寧な印象です。", "id": "Senang bertemu dengan Anda.", "ja": "お会いできてうれしいです。", "audio": "audio/cult/c02.mp3"}, {"title": "右手を使う", "body": "物の受け渡しや食事は右手で行います。", "id": "Silakan, pakai tangan kanan.", "ja": "どうぞ、右手を使ってください。", "audio": "audio/cult/c03.mp3"}, {"title": "左手は避ける", "body": "左手は不浄とされるので避けます。", "id": "Maaf, jangan pakai tangan kiri.", "ja": "すみません、左手は使わないで。", "audio": "audio/cult/c04.mp3"}, {"title": "目上への敬意", "body": "年上には少しかがんで敬意を示します。", "id": "Permisi, Pak.", "ja": "失礼します（男性へ）。", "audio": "audio/cult/c05.mp3"}, {"title": "名前を尋ねる", "body": "会話は名前を聞くところから。", "id": "Nama Anda siapa?", "ja": "お名前は？", "audio": "audio/cult/c06.mp3"}, {"title": "出身を聞く", "body": "出身地の話題は喜ばれます。", "id": "Anda berasal dari mana?", "ja": "ご出身はどちらですか？", "audio": "audio/cult/c07.mp3"}, {"title": "宗教への配慮", "body": "世界最大のイスラム教徒人口をもつ国です。", "id": "Saya menghormati agama Anda.", "ja": "あなたの宗教を尊重します。", "audio": "audio/cult/c08.mp3"}, {"title": "礼拝の時間", "body": "1日5回の礼拝(sholat)があります。", "id": "Sekarang waktu sholat.", "ja": "今は礼拝の時間です。", "audio": "audio/cult/c09.mp3"}, {"title": "ラマダン", "body": "断食月は日中の飲食を人前で控えめに。", "id": "Selamat menunaikan ibadah puasa.", "ja": "断食、頑張ってください。", "audio": "audio/cult/c10.mp3"}, {"title": "ハラル", "body": "豚肉や酒を避ける人が多いです。", "id": "Apakah makanan ini halal?", "ja": "この料理はハラルですか？", "audio": "audio/cult/c11.mp3"}, {"title": "モスク訪問", "body": "肌の露出を控え、靴を脱ぎます。", "id": "Boleh saya masuk masjid?", "ja": "モスクに入ってもいいですか？", "audio": "audio/cult/c12.mp3"}, {"title": "チップ", "body": "必須ではありませんが少額が喜ばれます。", "id": "Ini untuk Anda, terima kasih.", "ja": "これはあなたに、ありがとう。", "audio": "audio/cult/c13.mp3"}, {"title": "値切り（市場）", "body": "笑顔で交渉するのが礼儀です。", "id": "Boleh kurang sedikit?", "ja": "少し安くできますか？", "audio": "audio/cult/c14.mp3"}, {"title": "定価の店", "body": "スーパーなどでは値切れません。", "id": "Di sini harga pas.", "ja": "ここは定価です。", "audio": "audio/cult/c15.mp3"}, {"title": "おごり文化", "body": "誘った人が払うこともあります。", "id": "Biar saya yang bayar.", "ja": "私が払いますよ。", "audio": "audio/cult/c16.mp3"}, {"title": "割り勘", "body": "若い世代は割り勘も。", "id": "Kita bayar sendiri-sendiri, ya.", "ja": "別々に払おうね。", "audio": "audio/cult/c17.mp3"}, {"title": "食事の誘い", "body": "「もう食べた？」は挨拶がわりです。", "id": "Sudah makan belum?", "ja": "もう食べた？", "audio": "audio/cult/c18.mp3"}, {"title": "食事を勧める", "body": "「どうぞ召し上がれ」。", "id": "Silakan makan.", "ja": "どうぞ召し上がれ。", "audio": "audio/cult/c19.mp3"}, {"title": "手食文化", "body": "地方では手で食べる習慣もあります。", "id": "Enak makan pakai tangan.", "ja": "手で食べると美味しい。", "audio": "audio/cult/c20.mp3"}, {"title": "甘い味付け", "body": "料理も飲み物も甘めが好まれます。", "id": "Tehnya manis sekali.", "ja": "お茶がとても甘い。", "audio": "audio/cult/c21.mp3"}, {"title": "辛い料理", "body": "サンバルで辛さを足します。", "id": "Tolong, jangan terlalu pedas.", "ja": "あまり辛くしないで。", "audio": "audio/cult/c22.mp3"}, {"title": "屋台（warung）", "body": "安くて美味しい庶民の味です。", "id": "Warung ini murah dan enak.", "ja": "この屋台は安くて美味しい。", "audio": "audio/cult/c23.mp3"}, {"title": "靴を脱ぐ", "body": "家に上がるときは靴を脱ぎます。", "id": "Sepatunya dilepas di sini, ya.", "ja": "靴はここで脱いでね。", "audio": "audio/cult/c24.mp3"}, {"title": "家に招かれたら", "body": "手土産があると好印象です。", "id": "Ini oleh-oleh untuk Anda.", "ja": "これはお土産です。", "audio": "audio/cult/c25.mp3"}, {"title": "頭を触らない", "body": "子どもの頭も触らないのが無難。", "id": "Maaf, jangan pegang kepala.", "ja": "すみません、頭に触らないで。", "audio": "audio/cult/c26.mp3"}, {"title": "指し示し方", "body": "人差し指でなく親指で示します。", "id": "Yang itu, ya.", "ja": "あれです。", "audio": "audio/cult/c27.mp3"}, {"title": "呼びかけ", "body": "「すみません」で注意を引きます。", "id": "Permisi, numpang tanya.", "ja": "すみません、少し尋ねます。", "audio": "audio/cult/c28.mp3"}, {"title": "笑顔の力", "body": "笑顔で一気に打ち解けます。", "id": "Orang Indonesia suka tersenyum.", "ja": "インドネシア人は笑顔が好き。", "audio": "audio/cult/c29.mp3"}, {"title": "遠回しな断り", "body": "はっきりNoと言わない傾向があります。", "id": "Mungkin lain kali, ya.", "ja": "また今度にしましょう。", "audio": "audio/cult/c30.mp3"}, {"title": "ゴムの時間", "body": "時間感覚はややゆるやか（jam karet）。", "id": "Maaf, saya sedikit terlambat.", "ja": "すみません、少し遅れます。", "audio": "audio/cult/c31.mp3"}, {"title": "相互扶助", "body": "gotong royong＝助け合いの文化。", "id": "Mari kita gotong royong.", "ja": "助け合いましょう。", "audio": "audio/cult/c32.mp3"}, {"title": "大家族", "body": "家族・親族をとても大切にします。", "id": "Keluarga sangat penting di sini.", "ja": "ここでは家族がとても大切。", "audio": "audio/cult/c33.mp3"}, {"title": "敬称", "body": "年上の男性はPak、女性はBu。", "id": "Terima kasih banyak, Pak.", "ja": "本当にありがとうございます（男性へ）。", "audio": "audio/cult/c34.mp3"}, {"title": "若者言葉", "body": "くだけた語(nggak, aja)もよく使います。", "id": "Nggak apa-apa, santai aja.", "ja": "大丈夫、気楽にね。", "audio": "audio/cult/c35.mp3"}, {"title": "あいづち", "body": "iya/oh ya で会話を促します。", "id": "Oh ya? Terus?", "ja": "そうなの？それで？", "audio": "audio/cult/c36.mp3"}, {"title": "写真マナー", "body": "撮る前に一言かけます。", "id": "Boleh saya foto?", "ja": "写真を撮ってもいい？", "audio": "audio/cult/c37.mp3"}, {"title": "連絡手段", "body": "連絡はWhatsAppが主流です。", "id": "Boleh minta nomor WhatsApp?", "ja": "WhatsAppの番号をもらえますか？", "audio": "audio/cult/c38.mp3"}, {"title": "移動手段", "body": "バイクと配車アプリが日常です。", "id": "Saya pesan ojek online saja.", "ja": "オジェックを呼びますね。", "audio": "audio/cult/c39.mp3"}, {"title": "渋滞", "body": "都市部は渋滞が激しいです。", "id": "Jalanan macet sekali hari ini.", "ja": "今日は道がすごく渋滞。", "audio": "audio/cult/c40.mp3"}, {"title": "天気の話", "body": "雨季と乾季が話題になります。", "id": "Sekarang musim hujan, ya.", "ja": "今は雨季ですね。", "audio": "audio/cult/c41.mp3"}, {"title": "独立記念日", "body": "8月17日は大きな行事です。", "id": "Selamat Hari Kemerdekaan!", "ja": "独立記念日おめでとう！", "audio": "audio/cult/c42.mp3"}, {"title": "断食明け", "body": "Idul Fitriは最大の祝日です。", "id": "Selamat Idul Fitri, ya.", "ja": "断食明けおめでとう。", "audio": "audio/cult/c43.mp3"}, {"title": "服装", "body": "場面に合わせ控えめが無難です。", "id": "Sebaiknya pakai baju sopan.", "ja": "上品な服がいいですよ。", "audio": "audio/cult/c44.mp3"}, {"title": "バティック", "body": "正装にもなる伝統の布です。", "id": "Baju batik ini bagus sekali.", "ja": "このバティック、素敵ですね。", "audio": "audio/cult/c45.mp3"}, {"title": "冗談好き", "body": "ユーモアで距離が縮まります。", "id": "Anda lucu sekali!", "ja": "あなた面白いですね！", "audio": "audio/cult/c46.mp3"}, {"title": "褒め言葉", "body": "料理を褒めると喜ばれます。", "id": "Masakan Anda enak sekali.", "ja": "あなたの料理、すごく美味しい。", "audio": "audio/cult/c47.mp3"}, {"title": "別れ際", "body": "「また会いましょう」。", "id": "Sampai jumpa lagi, ya!", "ja": "また会おうね！", "audio": "audio/cult/c48.mp3"}, {"title": "見送りの言葉", "body": "「道中気をつけて」。", "id": "Hati-hati di jalan.", "ja": "道中気をつけて。", "audio": "audio/cult/c49.mp3"}];
